const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const xss = require('xss-clean');
const hpp = require('hpp');

const app = express();

// Security middleware
app.use(helmet());
app.use(xss());
app.use(hpp());

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});
app.use(limiter);

// Body parsing middleware
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Middleware for input validation
const validateInput = (req, res, next) => {
  // Basic input validation example
  if (req.body && typeof req.body === 'object') {
    // Sanitize inputs
    Object.keys(req.body).forEach(key => {
      if (typeof req.body[key] === 'string') {
        req.body[key] = req.body[key].trim();
      }
    });
  }

  // Validate query parameters
  if (req.query && typeof req.query === 'object') {
    Object.keys(req.query).forEach(key => {
      if (typeof req.query[key] === 'string') {
        req.query[key] = req.query[key].trim();
      }
    });
  }

  next();
};

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.status(200).json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Users endpoint with input validation and error handling
app.get('/users', validateInput, (req, res) => {
  try {
    // Simulate database operation with basic input validation
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Validate that we're sending valid data
    if (!Array.isArray(users)) {
      throw new Error('Invalid data structure returned');
    }

    // Sanitize user data for output
    const sanitizedUsers = users.map(user => ({
      id: user.id,
      name: sanitizeOutput(user.name),
      email: sanitizeOutput(user.email)
    }));

    res.status(200).json(sanitizedUsers);
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ 
      error: 'Failed to retrieve users',
      message: process.env.NODE_ENV === 'development' ? error.message : undefined
    });
  }
});

// Helper function to sanitize output data
function sanitizeOutput(str) {
  if (typeof str !== 'string') return str;
  // Remove potentially dangerous HTML/JS characters
  return str.replace(/[<>'"&]/g, (match) => {
    const escapeMap = {
      '<': '&lt;',
      '>': '&gt;',
      "'": '&#x27;',
      '"': '&quot;',
      '&': '&amp;'
    };
    return escapeMap[match];
  });
}

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);

  // Don't send stack traces in production
  const errorMsg = process.env.NODE_ENV === 'development' ? error.message : 'Internal server error';

  res.status(500).json({
    error: 'Internal server error',
    message: errorMsg
  });
});

// Handle 404 for undefined routes
app.use('*', (req, res) => {
  res.status(404).json({ 
    error: 'Route not found' 
  });
});

// Server startup with error handling
