    // Input validation
    if (page < 1 || isNaN(page)) {
      return res.status(400).json({ error: 'Invalid page parameter' });
    }

    if (limit < 1 || limit > 100 || isNaN(limit)) {
      return res.status(400).json({ error: 'Invalid limit parameter. Must be between 1 and 100' });
