const express = require('express');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const xss = require('xss-clean');
const hpp = require('hpp');

const app = express();

// Security middleware
app.use(helmet()); // Set security headers
app.use(xss()); // Prevent XSS attacks
app.use(hpp()); // Prevent HTTP Parameter Pollution

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100 // limit each IP to 100 requests per windowMs
});
app.use(limiter);

// Body parsing middleware
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.status(200).json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Users endpoint with proper validation and error handling
app.get('/users', (req, res) => {
  try {
    // Input validation - ensure query parameters are valid
    const { page, limit } = req.query;

    // Validate pagination parameters
    if (page && (isNaN(page) || page < 1)) {
      return res.status(400).json({ 
        error: 'Invalid page parameter. Must be a positive number.' 
      });
    }

    if (limit && (isNaN(limit) || limit < 1 || limit > 100)) {
      return res.status(400).json({ 
        error: 'Invalid limit parameter. Must be between 1 and 100.' 
      });
    }

    // Simulate data processing with proper error handling
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.status(200).json({
      users,
      pagination: {
        page: page ? parseInt(page) : 1,
        limit: limit ? parseInt(limit) : 10,
        total: users.length
      }
    });
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ 
      error: 'Failed to retrieve users', 
      message: process.env.NODE_ENV === 'development' ? error.message : undefined 
    });
  }
});

// Global error handler
app.use((error, req, res, next) => {
  console.error('Unhandled error:', error);
  res.status(500).json({ 
    error: 'Internal server error',
    message: process.env.NODE_ENV === 'development' ? error.message : undefined
  });
});

// 404 handler
app.use('*', (req, res) => {
  res.status(404).json({ error: 'Route not found' });
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  process.exit(0);
});

process.on('SIGINT', () => {
  console.log('SIGINT received, shutting down gracefully');
  process.exit(0);
});

module.exports = app;

